// Title: AXI4 Enumeration Types
//

//------------------------------------------------------------------------------
//
// Enum: axi4_prot_e
//
//------------------------------------------------------------------------------
//  Protection type mapped to the AxPROT signals (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.7))
//  
// AXI4_NORM_SEC_DATA - Normal/Secure/Data
// AXI4_PRIV_SEC_DATA - Privileged/Secure/Data
// AXI4_NORM_NONSEC_DATA - Normal/Non-secure/Data
// AXI4_PRIV_NONSEC_DATA - Privileged/Non-secure/Data
// AXI4_NORM_SEC_INST - Normal/Secure/Instruction
// AXI4_PRIV_SEC_INST - Privileged/Secure/Instruction
// AXI4_NORM_NONSEC_INST - Normal/Non-secure/Instruction
// AXI4_PRIV_NONSEC_INST - Privileged/Non-secure/Instruction
//  
typedef enum bit [2:0]
{
    AXI4_NORM_SEC_DATA    = 3'h0,
    AXI4_PRIV_SEC_DATA    = 3'h1,
    AXI4_NORM_NONSEC_DATA = 3'h2,
    AXI4_PRIV_NONSEC_DATA = 3'h3,
    AXI4_NORM_SEC_INST    = 3'h4,
    AXI4_PRIV_SEC_INST    = 3'h5,
    AXI4_NORM_NONSEC_INST = 3'h6,
    AXI4_PRIV_NONSEC_INST = 3'h7
} axi4_prot_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_response_e
//
//------------------------------------------------------------------------------
//  Response type mapped to the xRESP signals (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.4)
// 
// AXI4_OKAY   - Normal access has been successful, or exclusive access has failed (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.4).
// AXI4_EXOKAY - Exclusive acess okay (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.4)) OR Reserved value if QVIP BFM is configured as axi4lite interface (see AMBA AXI and ACE Protocol Specification IHI0022D section B1.1.1.
// AXI4_SLVERR - Slave signals an error to the originating master.
// AXI4_DECERR - Decode error (generally used to indicate that there is no slave at the transaction address).
//  
typedef enum bit [1:0]
{
    AXI4_OKAY   = 2'h0,
    AXI4_EXOKAY = 2'h1,
    AXI4_SLVERR = 2'h2,
    AXI4_DECERR = 2'h3
} axi4_response_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_rw_e
//
//------------------------------------------------------------------------------
//  This is used as the <read_or_write> argument to the <axi4_master_rw_transaction> transaction to indicate read or write.
// 
// AXI4_TRANS_READ - read transaction
// AXI4_TRANS_WRITE - write transaction
//  
typedef enum bit [0:0]
{
    AXI4_TRANS_READ  = 1'h0,
    AXI4_TRANS_WRITE = 1'h1
} axi4_rw_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_size_e
//
//------------------------------------------------------------------------------
//  Word-size encoding mapped to the AxSIZE signals (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.1). 
// 
// AXI4_BYTES_1 - 3'b000 i.e. 1 byte
// AXI4_BYTES_2 - 3'b001 i.e. 2 bytes
// AXI4_BYTES_4 - 3'b010 i.e. 4 bytes
// AXI4_BYTES_8 - 3'b011 i.e. 8 bytes
// AXI4_BYTES_16 - 3'b100 i.e. 16 bytes
// AXI4_BYTES_32 - 3'b101 i.e. 32 bytes
// AXI4_BYTES_64 - 3'b110 i.e. 64 bytes
// AXI4_BYTES_128 - 3'b111 i.e. 128 bytes
// 
typedef enum bit [2:0]
{
    AXI4_BYTES_1   = 3'h0,
    AXI4_BYTES_2   = 3'h1,
    AXI4_BYTES_4   = 3'h2,
    AXI4_BYTES_8   = 3'h3,
    AXI4_BYTES_16  = 3'h4,
    AXI4_BYTES_32  = 3'h5,
    AXI4_BYTES_64  = 3'h6,
    AXI4_BYTES_128 = 3'h7
} axi4_size_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_cache_e
//
//------------------------------------------------------------------------------
//  Cache behaviour type, mapped to the AxCACHE signals (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.4).
// 
// This has identical values to those in AXI3, but the AxCACHE[1] bit is now named 'Modifiable' (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.3.1)
// 
// AXI4_NONMODIFIABLE_NONBUF - Non-modifiable and non-bufferable
// AXI4_BUF_ONLY - Bufferable only
// AXI4_CACHE_2 - Bit pattern 0010
// AXI4_CACHE_3 - Bit pattern 0011
// AXI4_CACHE_RSVD_4 - Reserved
// AXI4_CACHE_RSVD_5 - Reserved
// AXI4_CACHE_6 - Bit pattern 0110
// AXI4_CACHE_7 - Bit pattern 0111
// AXI4_CACHE_RSVD_8 - Reserved
// AXI4_CACHE_RSVD_9 - Reserved
// AXI4_CACHE_10 - Bit pattern 1010
// AXI4_CACHE_11 - Bit pattern 1011
// AXI4_CACHE_RSVD_12 - Reserved
// AXI4_CACHE_RSVD_13 - Reserved
// AXI4_CACHE_14 - Bit pattern 1110
// AXI4_CACHE_15 - Bit pattern 1111
// 
typedef enum bit [3:0]
{
    AXI4_NONMODIFIABLE_NONBUF = 4'h0,
    AXI4_BUF_ONLY             = 4'h1,
    AXI4_CACHE_2              = 4'h2,
    AXI4_CACHE_3              = 4'h3,
    AXI4_CACHE_RSVD_4         = 4'h4,
    AXI4_CACHE_RSVD_5         = 4'h5,
    AXI4_CACHE_6              = 4'h6,
    AXI4_CACHE_7              = 4'h7,
    AXI4_CACHE_RSVD_8         = 4'h8,
    AXI4_CACHE_RSVD_9         = 4'h9,
    AXI4_CACHE_10             = 4'ha,
    AXI4_CACHE_11             = 4'hb,
    AXI4_CACHE_RSVD_12        = 4'hc,
    AXI4_CACHE_RSVD_13        = 4'hd,
    AXI4_CACHE_14             = 4'he,
    AXI4_CACHE_15             = 4'hf
} axi4_cache_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_burst_e
//
//------------------------------------------------------------------------------
//  Burst type mapped to the AxBURST signals to determine address calculation (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.4). 
// 
// AXI4_FIXED - Fixed
// AXI4_INCR - Incrementing
// AXI4_WRAP - Wrap
// AXI4_RESERVED - Reserved value. May be enabled by setting the configuration parameter <config_enable_burst_reserved_value>.
// 
typedef enum bit [1:0]
{
    AXI4_FIXED    = 2'h0,
    AXI4_INCR     = 2'h1,
    AXI4_WRAP     = 2'h2,
    AXI4_RESERVED = 2'h3
} axi4_burst_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_lock_e
//
//------------------------------------------------------------------------------
//  Access type mapped to the AxLOCK signals (see AMBA AXI and ACE Protocol Specification IHI0022D section A7.4).
// 
// AXI4_NORMAL - Normal Access, respecting barriers
// AXI4_EXCLUSIVE - Exclusive Access, respecting barriers
// 
typedef enum bit [1:0]
{
    AXI4_NORMAL    = 2'h0,
    AXI4_EXCLUSIVE = 2'h1
} axi4_lock_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_interface_type_e
//
//------------------------------------------------------------------------------
//  Type to configure the category of the interface (see AMBA AXI and ACE Protocol Specification IHI0022D section A10.2) as read/write, read-only or write-only by setting the value of <config_interface_type> configuration parameter.
// 
// AXI4_READWRITE - Read and Write
// AXI4_READONLY - Read Only
// AXI4_WRITEONLY - Write Only
// 
typedef enum bit [1:0]
{
    AXI4_READWRITE = 2'h0,
    AXI4_READONLY  = 2'h1,
    AXI4_WRITEONLY = 2'h2
} axi4_interface_type_e;



//------------------------------------------------------------------------------
//
// Enum: axi4_assertion_e
//
//------------------------------------------------------------------------------
//  Type defining the error messages which can be produced by the <mgc_axi4> Questa Verification IP.
// 
// Individual error messages can be disabled using the <config_enable_assertion> array of configuration bits.
// 
// AXI4_ADDRESS_WIDTH_EXCEEDS_64                               -  60000 -  AXI4 supports up to 64-bit addressing (see AMBA AXI and ACE Protocol Specification IHI0022D section A10.3.1)
// AXI4_ARADDR_CHANGED_BEFORE_ARREADY                          -  60001 -  The value of <ARADDR> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARADDR_UNKN                                            -  60002 -  <ARADDR> has an X value/<ARADDR> has an Z value
// AXI4_ARPROT_CHANGED_BEFORE_ARREADY                          -  60003 -  The value of <ARPROT> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARPROT_UNKN                                            -  60004 -  <ARPROT> has an X value/<ARPROT> has an Z value
// AXI4_ARREADY_NOT_ASSERTED_AFTER_ARVALID                     -  60005 -  Once <ARVALID> has been asserted, <ARREADY> should be asserted within <config_max_latency_ARVALID_assertion_to_ARREADY> clock periods
// AXI4_ARREADY_UNKN                                           -  60006 -  <ARREADY> has an X value/<ARREADY> has a Z value
// AXI4_ARVALID_DEASSERTED_BEFORE_ARREADY                      -  60007 -  <ARVALID> has been de-asserted before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARVALID_HIGH_ON_FIRST_CLOCK                            -  60008 -  A master interface must begin driving <ARVALID> high only at a rising clock edge after <ARESETn> is HIGH (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_ARVALID_UNKN                                           -  60009 -  <ARVALID> has an X value/<ARVALID> has an Z value
// AXI4_AWADDR_CHANGED_BEFORE_AWREADY                          -  60010 -  The value of <AWADDR> has changed from its initial value between the time <AWVALID> was asserted, and before <AWREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_AWADDR_UNKN                                            -  60011 -  <AWADDR> has an X value/<AWADDR> has an Z value
// AXI4_AWPROT_CHANGED_BEFORE_AWREADY                          -  60012 -  The value of <AWPROT> has changed from its initial value between the time <AWVALID> was asserted, and before <AWREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_AWPROT_UNKN                                            -  60013 -  <AWPROT> has an X value/<AWPROT> has an Z value
// AXI4_AWREADY_NOT_ASSERTED_AFTER_AWVALID                     -  60014 -  Once <AWVALID> has been asserted, <AWREADY> should be asserted within <config_max_latency_AWVALID_assertion_to_AWREADY> clock periods
// AXI4_AWREADY_UNKN                                           -  60015 -  <AWREADY> has an X value/<AWREADY> has an Z value
// AXI4_AWVALID_DEASSERTED_BEFORE_AWREADY                      -  60016 -  <AWVALID> has been de-asserted before <AWREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_AWVALID_HIGH_ON_FIRST_CLOCK                            -  60017 -  A master interface must begin driving <AWVALID> high only at a rising clock edge after <ARESETn> is HIGH (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_AWVALID_UNKN                                           -  60018 -  <AWVALID> has an X value/<AWVALID> has an Z value
// AXI4_BREADY_NOT_ASSERTED_AFTER_BVALID                       -  60019 -  Once <BVALID> has been asserted, <BREADY> should be asserted within <config_max_latency_BVALID_assertion_to_BREADY> clock periods
// AXI4_BREADY_UNKN                                            -  60020 -  <BREADY> has an X value/<BREADY> has an Z value
// AXI4_BRESP_CHANGED_BEFORE_BREADY                            -  60021 -  The value of <BRESP> has changed from its initial value between the time <BVALID> was asserted, and before <BREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_BRESP_UNKN                                             -  60022 -  <BRESP> has an X value/<BRESP> has a Z value
// AXI4_BVALID_DEASSERTED_BEFORE_BREADY                        -  60023 -  <BVALID> has been de-asserted before <BREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_BVALID_HIGH_EXITING_RESET                              -  60024 -  <BVALID> should have been driven low when exiting reset (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_BVALID_UNKN                                            -  60025 -  <BVALID> has an X value/<BVALID> has a Z value
// AXI4_DEC_ERR_RESP_FOR_READ                                  -  60026 -  No slave at the address for this read transfer (signaled by <AXI4_DECERR>)
// AXI4_DEC_ERR_RESP_FOR_WRITE                                 -  60027 -  No slave at the address for this write transfer (signaled by <AXI4_DECERR>)
// AXI4_EXOKAY_RESPONSE_NORMAL_READ                            -  60028 -  Slave has responded <AXI4_EXOKAY> to a non exclusive read transfer
// AXI4_EXOKAY_RESPONSE_NORMAL_WRITE                           -  60029 -  Slave has responded <AXI4_EXOKAY> to a non exclusive write transfer 
// AXI4_INVALID_WRITE_STROBES_ON_UNALIGNED_WRITE_TRANSFER      -  60030 -  Write strobe(s) incorrect for address/size of an unaligned transaction (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.3)
// AXI4_MINIMUM_SLAVE_ADDRESS_SPACE_VIOLATION                  -  60031 -  The minimum address space occupied by a single slave device is 4 kilobytes (see AMBA AXI and ACE Protocol Specification IHI0022D section A10.3.2)
// AXI4_PARAM_READ_DATA_BUS_WIDTH                              -  60032 -  The value of <AXI4_RDATA_WIDTH> must be either 32 or 64 (see AMBA AXI and ACE Protocol Specification IHI0022D section B1.1.2)
// AXI4_PARAM_WRITE_DATA_BUS_WIDTH                             -  60033 -  The value of <AXI4_WDATA_WIDTH> must be either 32 or 64 (see AMBA AXI and ACE Protocol Specification IHI0022D section B1.1.2)
// AXI4_READ_DATA_BEFORE_ADDRESS                               -  60034 -  An unexpected read response has occurred (there are no outstanding read transactions with this id) (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.3)
// AXI4_READ_DATA_CHANGED_BEFORE_RREADY                        -  60035 -  The value of <RDATA> has changed from its initial value between the time <RVALID> was asserted, and before <RREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_READ_DATA_UNKN                                         -  60036 -  <RDATA> has an X value/<RDATA> has a Z value
// AXI4_READ_RESP_CHANGED_BEFORE_RREADY                        -  60037 -  The value of <RRESP> has changed from its initial value between the time <RVALID> was asserted, and before <RREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_RREADY_NOT_ASSERTED_AFTER_RVALID                       -  60038 -  Once <RVALID> has been asserted, <RREADY> should be asserted within <config_max_latency_RVALID_assertion_to_RREADY> clock periods
// AXI4_RREADY_UNKN                                            -  60039 -  <RREADY> has an X value/<RREADY> has a Z value
// AXI4_RRESP_UNKN                                             -  60040 -  <RRESP> has an X value/<RRESP> has a Z value
// AXI4_RVALID_DEASSERTED_BEFORE_RREADY                        -  60041 -  <RVALID> has been de-asserted before <RREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_RVALID_HIGH_EXITING_RESET                              -  60042 -  <RVALID> should have been driven low when exiting reset (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_RVALID_UNKN                                            -  60043 -  <RVALID> has an X value/<RVALID> has a Z value
// AXI4_SLV_ERR_RESP_FOR_READ                                  -  60044 -  Slave has detected an error for this read transfer (signaled by <AXI4_SLVERR>)
// AXI4_SLV_ERR_RESP_FOR_WRITE                                 -  60045 -  Slave has detected an error for this write transfer (signaled by <AXI4_SLVERR>)
// AXI4_TIMEOUT_WAITING_FOR_READ_RESPONSE                      -  60046 -  Timed-out waiting for a read response (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.6)
// AXI4_TIMEOUT_WAITING_FOR_WRITE_RESPONSE                     -  60047 -  Timed-out waiting for a write response (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.6)
// AXI4_WDATA_CHANGED_BEFORE_WREADY_ON_INVALID_LANE            -  60048 -  On a lane whose strobe is 0, the value of <WDATA> has changed from its initial value between the time <WVALID> was asserted, and before <WREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_WDATA_CHANGED_BEFORE_WREADY_ON_VALID_LANE              -  60049 -  On a lane whose strobe is 1, the value of <WDATA> has changed from its initial value between the time <WVALID> was asserted, and before <WREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_WREADY_NOT_ASSERTED_AFTER_WVALID                       -  60050 -  Once <WVALID> has been asserted, <WREADY> should be asserted within <config_max_latency_WVALID_assertion_to_WREADY> clock periods
// AXI4_WREADY_UNKN                                            -  60051 -  <WREADY> has an X value/<WREADY> has a Z value
// AXI4_WRITE_DATA_BEFORE_ADDRESS                              -  60052 -  A write data beat has occurred before the corresponding address phase
// AXI4_WRITE_DATA_UNKN_ON_INVALID_LANE                        -  60053 -  DEPRECATED - This assertion is now DEPRECATED and by default DISABLED, as per protocol Byte lanes for which strobe is 0 could take unknown value..
// AXI4_WRITE_DATA_UNKN_ON_VALID_LANE                          -  60054 -  On a lane whose strobe is 1, <WDATA> has an X value/<WDATA> has a Z value
// AXI4_WRITE_RESPONSE_WITHOUT_ADDR_DATA                       -  60055 -  An unexpected write response has occurred (there are no outstanding write transactions with this id) 
// AXI4_WSTRB_CHANGED_BEFORE_WREADY                            -  60056 -  The value of <WSTRB> has changed from its initial value between the time <WVALID> was asserted, and before <WREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_WSTRB_UNKN                                             -  60057 -  <WSTRB> has an X value/<WSTRB> has an Z value
// AXI4_WVALID_DEASSERTED_BEFORE_WREADY                        -  60058 -  <WVALID> has been de-asserted before <WREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_WVALID_HIGH_ON_FIRST_CLOCK                             -  60059 -  A master interface must begin driving <WVALID> high only at a rising clock edge after <ARESETn> is HIGH (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_WVALID_UNKN                                            -  60060 -  <WVALID> has an X value/<WVALID> has an Z value
// MVC_FAILED_POSTCONDITION                                    -  60061 -  A postcondition failed
// MVC_FAILED_RECOGNITION                                      -  60062 -  An item failed to be recognized  
// AXI4_DEC_ERR_ILLEGAL_FOR_MAPPED_SLAVE_ADDR                  -  60063 -  Slave receives a burst to a mapped address but responds with DECERR (signaled by <AXI4_DECERR>) (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.4)
// AXI4_AWVALID_HIGH_DURING_RESET                              -  60064 -  AWVALID asserted during the reset state (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_WVALID_HIGH_DURING_RESET                               -  60065 -  WVALID asserted during the reset state (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_BVALID_HIGH_DURING_RESET                               -  60066 -  BVALID asserted during the reset state (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_ARVALID_HIGH_DURING_RESET                              -  60067 -  ARVALID asserted during the reset state (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_RVALID_HIGH_DURING_RESET                               -  60068 -  RVALID asserted during the reset state (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.1.2)
// AXI4_TIMEOUT_WAITING_FOR_WRITE_DATA                         -  60069 -  Timed-out waiting for a data phase in write data burst (see AMBA AXI and ACE Protocol Specification IHI0022D section A4.6)
// AXI4_TIMEOUT_WAITING_FOR_WRITE_ADDR_AFTER_DATA              -  60070 -  Timed-out waiting for a write address phase to be coming after data see AMBA AXI and ACE Protocol Specification IHI0022D section A2.2
// AXI4_ARESETn_SIGNAL_Z                                       -  60071 -  AXI4 Reset signal has z value
// AXI4_ARESETn_SIGNAL_X                                       -  60072 -  AXI4 Reset signal has x value
// AXI4_ADDR_FOR_READ_BURST_ACROSS_4K_BOUNDARY                 -  60073 -  This read transaction has crossed a 4KB boundary (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.1) 
// AXI4_ADDR_FOR_WRITE_BURST_ACROSS_4K_BOUNDARY                -  60074 -  This write transaction has crossed a 4KB boundary (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.4.1)
// AXI4_ARADDR_FALLS_IN_REGION_HOLE                            -  60075 -  The <ARADDR> value cannot be decoded to a region in the region map (see AMBA AXI and ACE Protocol Specification IHI0022D section A8.2.1)
// AXI4_ARBURST_CHANGED_BEFORE_ARREADY                         -  60076 -  The value of <ARBURST> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARBURST_UNKN                                           -  60077 -  <ARBURST> has an X value/<ARBURST> has an Z value
// AXI4_ARCACHE_CHANGED_BEFORE_ARREADY                         -  60078 -  The value of <ARCACHE> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARCACHE_UNKN                                           -  60079 -  <ARCACHE> has an X value/<ARCACHE> has an Z value
// AXI4_ARID_CHANGED_BEFORE_ARREADY                            -  60080 -  The value of <ARID> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARID_UNKN                                              -  60081 -  <ARID> has an X value/<ARID> has an Z value
// AXI4_ARLEN_CHANGED_BEFORE_ARREADY                           -  60082 -   The value of <ARLEN> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARLEN_UNKN                                             -  60083 -  <ARLEN> has an X value/<ARLEN> has an Z value
// AXI4_ARLOCK_CHANGED_BEFORE_ARREADY                          -  60084 -  The value of <ARLOCK> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARLOCK_UNKN                                            -  60085 -  <ARLOCK> has an X value/<ARLOCK> has an Z value
// AXI4_ARQOS_CHANGED_BEFORE_ARREADY                           -  60086 -  The value of <ARQOS>  has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARQOS_UNKN                                             -  60087 -  <ARQOS>  has an X value/<ARQOS> has an Z value
// AXI4_ARREGION_CHANGED_BEFORE_ARREADY                        -  60088 -  The value of <ARREGION> has changed from its initial value between the time <ARVALID> was asserted, and before <ARREADY> was asserted (see AMBA AXI and ACE Protocol Specification IHI0022D section A3.2.1)
// AXI4_ARREGION_MISMATCH                                      -  60089 -  The <ARREGION> value does not match the value defined in the region map (see AMBA AXI and ACE Protocol Specification IHI0022D section A8.2.1)
// AXI4_ARREGION_UNKN                                          -  60090 -  <ARREGION> has an X value/<ARREGION> has an Z value
