import QUESTA_MVC::QUESTA_MVC_NEGEDGE;
import QUESTA_MVC::QUESTA_MVC_ANYEDGE;
import QUESTA_MVC::QUESTA_MVC_0_TO_1_EDGE;
import QUESTA_MVC::QUESTA_MVC_1_TO_0_EDGE;


(* cy_so="libaxi4_IN_SystemVerilog_MTI_full" *)
(* on_lib_load="axi4_IN_SystemVerilog_load" *)

interface mgc_common_axi4 #(int AXI4_ADDRESS_WIDTH = 64, int AXI4_RDATA_WIDTH = 1024, int AXI4_WDATA_WIDTH = 1024, int AXI4_ID_WIDTH = 18, int AXI4_USER_WIDTH = 8, int AXI4_REGION_MAP_SIZE = 16)
    (input wire iACLK, input wire iARESETn);

    //-------------------------------------------------------------------------
    //
    // Group: AXI4 Signals
    //
    //-------------------------------------------------------------------------



    //-------------------------------------------------------------------------
    // Private wires
    //-------------------------------------------------------------------------
    wire ACLK;
    wire ARESETn;
    wire AWVALID;
    wire [((AXI4_ADDRESS_WIDTH) - 1):0]  AWADDR;
    wire [2:0] AWPROT;
    wire [3:0] AWREGION;
    wire [7:0] AWLEN;
    wire [2:0] AWSIZE;
    wire [1:0] AWBURST;
    wire AWLOCK;
    wire [3:0] AWCACHE;
    wire [3:0] AWQOS;
    wire [((AXI4_ID_WIDTH) - 1):0]  AWID;
    wire [((AXI4_USER_WIDTH) - 1):0]  AWUSER;
    wire AWREADY;
    wire ARVALID;
    wire [((AXI4_ADDRESS_WIDTH) - 1):0]  ARADDR;
    wire [2:0] ARPROT;
    wire [3:0] ARREGION;
    wire [7:0] ARLEN;
    wire [2:0] ARSIZE;
    wire [1:0] ARBURST;
    wire ARLOCK;
    wire [3:0] ARCACHE;
    wire [3:0] ARQOS;
    wire [((AXI4_ID_WIDTH) - 1):0]  ARID;
    wire [((AXI4_USER_WIDTH) - 1):0]  ARUSER;
    wire ARREADY;
    wire RVALID;
    wire [((AXI4_RDATA_WIDTH) - 1):0]  RDATA;
    wire [1:0] RRESP;
    wire RLAST;
    wire [((AXI4_ID_WIDTH) - 1):0]  RID;
    wire [((AXI4_USER_WIDTH) - 1):0]  RUSER;
    wire RREADY;
    wire WVALID;
    wire [((AXI4_WDATA_WIDTH) - 1):0]  WDATA;
    wire [(((AXI4_WDATA_WIDTH / 8)) - 1):0]  WSTRB;
    wire WLAST;
    wire [((AXI4_USER_WIDTH) - 1):0]  WUSER;
    wire WREADY;
    wire BVALID;
    wire [1:0] BRESP;
    wire [((AXI4_ID_WIDTH) - 1):0]  BID;
    wire [((AXI4_USER_WIDTH) - 1):0]  BUSER;
    wire BREADY;



    // Propagate global signals onto interface wires
    assign ACLK = iACLK;
    assign ARESETn = iARESETn;

    //  Section: AXI4 Configuration
    // 


    // Variable: config_axi4lite_interface
    //
    //  This configuration can be enabled to use the AXI4 QVIP as AXI4-Lite.
    // Setting this variable to 1 enables the user to use the AXI4 BFM and all as AXI4-Lite
    // Setting this variable to 0 ensures usual usage as AXI4.
    //  
    // Default: false(behaves as AXI4 interface)
    // 
    //
    // mentor configurator specification name "Configure AXI4-Lite behaviour"
    bit config_axi4lite_interface;

    // 
    // //-----------------------------------------------------------------------------
    // Group: Enables
    // //-----------------------------------------------------------------------------
    // 


    // Variable: config_enable_slave_exclusive
    //
    //  Controls whether the slave supports exclusive accesses.
    // 
    // Default: true
    // 
    // This is set to true so that the slave will support exclusive
    // accesses by responding with <AXI4_EXOKAY>.
    // 
    // The coverage collected by the covergroup <axi4_cvg> is affected
    // by this parameter value setting.
    // 
    //
    // mentor configurator specification name "Enable Exclusive transaction support"
    bit config_enable_slave_exclusive;

    // Variable: config_enable_rlast
    //
    //  Controls whether the optional RLAST signal is used, or not.
    // 
    // <RLAST> is an optional input to the master, because the length of a read burst
    // is always known.
    // 
    //
    // mentor configurator specification name "Enable RLAST"
    bit config_enable_rlast;

    // Variable: config_enable_id
    //
    //  Controls whether the optional AWID, BID, ARID, RID signals are used, or not.
    // 
    //    It should be set to false in case these id fields are not supported.
    // 
    //
    // mentor configurator specification name "Enable ID fields"
    bit config_enable_id;

    // Variable: config_enable_all_assertions
    //
    // 
    // Enables or disables all assertion checks in QVIP. 
    // 
    // Default: Enabled
    // 
    //
    // mentor configurator specification name "Enable all protocol assertions"
    bit config_enable_all_assertions;

    // Variable: config_enable_assertion
    //
    // 
    // Enables or disables the specified assertion. This variable is an array of 
    // configuration parameters controlling whether specific assertions within 
    // Questa Verification IP (of type ~axi4_assertion_e~) can be enabled or disabled. This 
    // assertion is disabled as follows:
    // //-----------------------------------------------------------------------
    // // < BFM interface>.set_config_enable_assertion_index1(<name of assertion>,1'b0);
    // //-----------------------------------------------------------------------
    // 
    // For example, the assertion AXI4_READ_DATA_UNKN is disabled as follows:
    // <bfm>.set_config_enable_assertion_index1(AXI4_READ_DATA_UNKN, 1'b0); 
    // 
    // where bfm is the AXI4 interface instance name for which the assertion 
    // to be disabled. 
    // 
    // Default: Enabled
    // 
    //
    // mentor configurator specification name "Enable individual protocol assertion" 
    bit [255:0] config_enable_assertion;

    // 
    // //-----------------------------------------------------------------------------
    // Group: Slave behavior control
    // //-----------------------------------------------------------------------------
    // 


    // Variable: config_read_data_reordering_depth
    //
    //  Defines the read reordering depth of the slave end of the interface.
    // 
    // Responses from the first <config_read_data_reordering_depth> outstanding read
    // transactions, each with address <ARID> values different from any earlier
    // outstanding read transaction(as seen by the slave) are expected, interleaved
    // at random. A violation causes a <AXI4_READ_REORDERING_VIOLATION> error.
    // 
    // Default: (1 << AXI4_ID_WIDTH)
    // 
    // This is so that the slave is expected to process all transactions in
    // any order (up to uniqueness of <ARID>).
    // 
    // For a given <AXI4_ID_WIDTH> parameter value, the maximum possible value of
    // <config_read_data_reordering_depth> is 2**AXI4_ID_WIDTH. The
    // <AXI4_PARAM_READ_REORDERING_DEPTH_EXCEEDS_MAX_ID> error report will be issued
    // if <config_read_data_reordering_depth> exceeds this value.
    // 
    // If the user-supplied value is 0, the
    // <AXI4_PARAM_READ_REORDERING_DEPTH_EQUALS_ZERO> error will be issued, and the
    // value will be set to 1.
    // 
    //
    // mentor configurator specification name "Read data reordering depth"
    int unsigned config_read_data_reordering_depth;

    // 
    // //-----------------------------------------------------------------------------
    // Group: Timeout control
    // //-----------------------------------------------------------------------------
    // 


    // Variable: config_max_transaction_time_factor
    //
    //  Specifies the maximum timeout for any read or write transaction, which also 
    // includes all individual phases of the AXI interface. It is recommended to set 
    // this timeout to the maximum duration of a read or write transaction. 
    // 
    // This limits the duration of a transaction.
    // 
    // Default: 100000 clock periods 
    //
    // mentor configurator specification name "Timeout for complete Read/Write transaction (in terms of ACLK)"
    int unsigned config_max_transaction_time_factor;

    // Variable: config_burst_timeout_factor
    //
    // 
    // Specifies the maximum delay between the individual phases of the AXI4 
    // transactions in terms of the clock ACLK clock period. The delay is from the end 
    // of one phase to the start of the second phase. 
    // 
    // For example, after the end of the read address channel phase, the read data
    // burst should start within ~config_burst_timeout_factor~ number of clock
    // cycles. 
    // 
    // Default: 10000 
    // 
    //
    // mentor configurator specification name "Burst timeout between individual phases of a transaction (in terms of ACLK)"
    int unsigned config_burst_timeout_factor;

    // Variable: config_max_latency_AWVALID_assertion_to_AWREADY
    //
    //  Defines the timeout (in clock periods) from the assertion of <AWVALID> to the
    //    assertion of <AWREADY>.
    // 
    //    Default 10000
    // 
    // The error message <AXI4_AWREADY_NOT_ASSERTED_AFTER_AWVALID> will be issued if
    // this period elapses from the assertion of <AWVALID>.
    // 
    //
    // mentor configurator specification name "Timeout from AWVALID to AWREADY assertion (in terms of ACLK)"
    int unsigned config_max_latency_AWVALID_assertion_to_AWREADY;

    // Variable: config_max_latency_ARVALID_assertion_to_ARREADY
    //
    //  Defines the timeout (in clock periods) from the
    //    assertion of <ARVALID> to the assertion of <ARREADY>.
    // 
    //    Default 10000
    // 
    // The error message <AXI4_ARREADY_NOT_ASSERTED_AFTER_ARVALID> will be issued if
    // this period elapses from the assertion of <ARVALID>.
    // 
    //
    // mentor configurator specification name "Timeout from ARVALID to ARREADY assertion (in terms of ACLK)"
    int unsigned config_max_latency_ARVALID_assertion_to_ARREADY;

    // Variable: config_max_latency_RVALID_assertion_to_RREADY
    //
    //  Defines the timeout (in clock periods) from the
    //    assertion of <RVALID> to the assertion of <RREADY>.
    // 
    //    Default 10000.
    // 
    // The error message <AXI4_RREADY_NOT_ASSERTED_AFTER_RVALID> will be issued if
    // this period elapses from the assertion of <RVALID>.
    // 
    //
    // mentor configurator specification name "Timeout from RVALID to RREADY assertion (in terms of ACLK)"
    int unsigned config_max_latency_RVALID_assertion_to_RREADY;

    // Variable: config_max_latency_BVALID_assertion_to_BREADY
    //
    //  Defines the timeout (in clock periods) from the assertion of <BVALID> to the 
    //    assertion of <BREADY>.
    // 
    //    Default 10000.
    // 
    // The error message <AXI4_BREADY_NOT_ASSERTED_AFTER_BVALID> will be issued if
    // this period elapses from the assertion of <BVALID>.
    // 
    //
    // mentor configurator specification name "Timeout from BVALID to BREADY assertion (in terms of ACLK)"
    int unsigned config_max_latency_BVALID_assertion_to_BREADY;

    // Variable: config_max_latency_WVALID_assertion_to_WREADY
    //
    //  Defines the timeout (in clock periods) from the assertion of <WVALID> to the 
    //    assertion of <WREADY>.
    // 
    //    Default 10000.
    // 
    // The error message <AXI4_WREADY_NOT_ASSERTED_AFTER_WVALID> will be issued if
    // this period elapses from the assertion of <WVALID>.
    // 
    //
    // mentor configurator specification name "Timeout from WVALID to WREADY assertion (in terms of ACLK)"
    int unsigned config_max_latency_WVALID_assertion_to_WREADY;

    // 
    // //-----------------------------------------------------------------------------
    // Group: QOS and Region control
    // //-----------------------------------------------------------------------------
    // 


    // Variable: config_enable_qos
    //
    //  Defines whether the master participates in the Quality-of-Service scheme. 
    // 
    // Default: true i.e. the master participates in the Quality-of-Service scheme. 
    // 
    // If a master does not participate, the <AWQOS>/<ARQOS> value used in
    // write/read transactions must be b0000.
    // 
    //
    // mentor configurator specification name "Enable Quality of Service support"
    bit config_enable_qos;

    // Variable: config_setup_time
    //
    //  Specifies the setup-time, in units of simulator time-steps, for all signals. 
    //  
    // Default: 0. 
    // 
    // Users should use the ~questa_mvc_sv_convert_to_precision~ function to set this
    // to the preferred time-interval.  See <Configuration of Time-Units> for
    // background on configuration of time-units.
    // 
    //
    // Note - This configuration variable is used in an expression involving time precision.
    //        To ensure its value is correct, use questa_mvc_sv_convert_to_precision API of QUESTA_MVC package.
    //
    longint unsigned config_setup_time;

    // Variable: config_hold_time
    //
    //  Specifies the hold-time, in units of simulator time-steps, for all signals. 
    //  
    // Default: 0. 
    // 
    // Users should use the ~questa_mvc_sv_convert_to_precision~ function to set this
    // to the preferred time-interval.  See <Configuration of Time-Units> for
    // background on configuration of time-units.
    // 
    //
    // Note - This configuration variable is used in an expression involving time precision.
    //        To ensure its value is correct, use questa_mvc_sv_convert_to_precision API of QUESTA_MVC package.
    //
    longint unsigned config_hold_time;

    // Variable: config_max_outstanding_wr
    //
    // Configures maximum possible outstanding Write transactions
    //
    int config_max_outstanding_wr;

    // Variable: config_max_outstanding_rd
    //
    // Configures maximum possible outstanding Read transactions
    //
    int config_max_outstanding_rd;

    // Variable: config_max_outstanding_rw
    //
    // Configures maximum possible outstanding Combined (Read and Write) transactions
    //
    int config_max_outstanding_rw;

    // Variable: config_num_outstanding_wr_phase
    //
    // Provides current number of outstanding Write address phases 
    //
    int config_num_outstanding_wr_phase;

    // Variable: config_num_outstanding_rd_phase
    //
    // Provides current number of outstanding Read address phases
    //
    int config_num_outstanding_rd_phase;

    // Variable: config_is_issuing
    //
    // Enables Master component to use "config_max_outstanding_wr/config_max_outstanding_rd/config_max_outstanding_rw" variables for transaction issuing capability when set to true
    //
    bit config_is_issuing;


    //-------------------------------------------------------------------------
    // Deprecated variables - writing to these variables will cause a warning to be issued.
    //-------------------------------------------------------------------------
    bit [((AXI4_ID_WIDTH) - 1):0]  config_axi4lite_tr_id;
    bit [((AXI4_ADDRESS_WIDTH) - 1):0]  config_slave_start_addr;
    bit [((AXI4_ADDRESS_WIDTH) - 1):0]  config_slave_end_addr;


    //-------------------------------------------------------------------------
    // Private variables
    //-------------------------------------------------------------------------
    axi4_interface_type_e config_interface_type;


    //------------------------------------------------------------------------------
    // Group:- Interface ends
    //------------------------------------------------------------------------------
    //
    longint axi4_master_end;


    // Function:- get_axi4_master_end
    //
    // Returns a handle to the <master> end of this instance of the <axi4> interface.

    function longint get_axi4_master_end();
        return axi4_master_end;
    endfunction

    longint axi4_slave_end;


    // Function:- get_axi4_slave_end
    //
    // Returns a handle to the <slave> end of this instance of the <axi4> interface.

    function longint get_axi4_slave_end();
        return axi4_slave_end;
    endfunction

    longint axi4_clock_source_end;


    // Function:- get_axi4_clock_source_end
    //
    // Returns a handle to the <clock_source> end of this instance of the <axi4> interface.

    function longint get_axi4_clock_source_end();
        return axi4_clock_source_end;
    endfunction

    longint axi4_reset_source_end;


    // Function:- get_axi4_reset_source_end
    //
    // Returns a handle to the <reset_source> end of this instance of the <axi4> interface.

    function longint get_axi4_reset_source_end();
        return axi4_reset_source_end;
    endfunction

    longint axi4__monitor_end;


    // Function:- get_axi4__monitor_end
    //
    // Returns a handle to the <_monitor> end of this instance of the <axi4> interface.

    function longint get_axi4__monitor_end();
        return axi4__monitor_end;
    endfunction


    // Group:- Abstraction Levels
    // 
    // These functions are used set or get the abstraction levels of an interface end.
    // See <Abstraction Levels of Interface Ends> for more details on the meaning of
    // TLM or WLM connected and the valid combinations.


    //-------------------------------------------------------------------------
    // Function:- axi4_set_master_abstraction_level
    //
    //     Function to set whether the <master> end of the interface is WLM
    //     or TLM connected. See <Abstraction Levels of Interface Ends> for a
    //     description of abstraction levels, how they affect the behaviour of the
    //     QVIP, and guidelines for setting them.
    //
    // Arguments:
    //    wire_level - Set to 1 to be WLM connected.
    //    TLM_level -  Set to 1 to be TLM connected.
    //
    function void axi4_set_master_abstraction_level
    (
        input bit          wire_level,
        input bit          TLM_level
    );
        axi4_set_master_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_get_master_abstraction_level
    //
    //     Function to return the Abstraction level setting for the <master> end.
    //     See <Abstraction Levels of Interface Ends> for a description of abstraction
    //     levels and how they affect the behaviour of the Questa Verification IP.
    //
    // Arguments:
    //
    //    wire_level - Value = 1 if this end is WLM connected.
    //    TLM_level -  Value = 1 if this end is TLM connected.
    //------------------------------------------------------------------------------
    function void axi4_get_master_abstraction_level
    (
        output bit         wire_level,
        output bit         TLM_level
    );
        axi4_get_master_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_set_slave_abstraction_level
    //
    //     Function to set whether the <slave> end of the interface is WLM
    //     or TLM connected. See <Abstraction Levels of Interface Ends> for a
    //     description of abstraction levels, how they affect the behaviour of the
    //     QVIP, and guidelines for setting them.
    //
    // Arguments:
    //    wire_level - Set to 1 to be WLM connected.
    //    TLM_level -  Set to 1 to be TLM connected.
    //
    function void axi4_set_slave_abstraction_level
    (
        input bit          wire_level,
        input bit          TLM_level
    );
        axi4_set_slave_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_get_slave_abstraction_level
    //
    //     Function to return the Abstraction level setting for the <slave> end.
    //     See <Abstraction Levels of Interface Ends> for a description of abstraction
    //     levels and how they affect the behaviour of the Questa Verification IP.
    //
    // Arguments:
    //
    //    wire_level - Value = 1 if this end is WLM connected.
    //    TLM_level -  Value = 1 if this end is TLM connected.
    //------------------------------------------------------------------------------
    function void axi4_get_slave_abstraction_level
    (
        output bit         wire_level,
        output bit         TLM_level
    );
        axi4_get_slave_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_set_clock_source_abstraction_level
    //
    //     Function to set whether the <clock_source> end of the interface is WLM
    //     or TLM connected. See <Abstraction Levels of Interface Ends> for a
    //     description of abstraction levels, how they affect the behaviour of the
    //     QVIP, and guidelines for setting them.
    //
    // Arguments:
    //    wire_level - Set to 1 to be WLM connected.
    //    TLM_level -  Set to 1 to be TLM connected.
    //
    function void axi4_set_clock_source_abstraction_level
    (
        input bit          wire_level,
        input bit          TLM_level
    );
        axi4_set_clock_source_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_get_clock_source_abstraction_level
    //
    //     Function to return the Abstraction level setting for the <clock_source> end.
    //     See <Abstraction Levels of Interface Ends> for a description of abstraction
    //     levels and how they affect the behaviour of the Questa Verification IP.
    //
    // Arguments:
    //
    //    wire_level - Value = 1 if this end is WLM connected.
    //    TLM_level -  Value = 1 if this end is TLM connected.
    //------------------------------------------------------------------------------
    function void axi4_get_clock_source_abstraction_level
    (
        output bit         wire_level,
        output bit         TLM_level
    );
        axi4_get_clock_source_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_set_reset_source_abstraction_level
    //
    //     Function to set whether the <reset_source> end of the interface is WLM
    //     or TLM connected. See <Abstraction Levels of Interface Ends> for a
    //     description of abstraction levels, how they affect the behaviour of the
    //     QVIP, and guidelines for setting them.
    //
    // Arguments:
    //    wire_level - Set to 1 to be WLM connected.
    //    TLM_level -  Set to 1 to be TLM connected.
    //
    function void axi4_set_reset_source_abstraction_level
    (
        input bit          wire_level,
        input bit          TLM_level
    );
        axi4_set_reset_source_end_abstraction_level( wire_level, TLM_level );
    endfunction

    //-------------------------------------------------------------------------
    // Function:- axi4_get_reset_source_abstraction_level
    //
    //     Function to return the Abstraction level setting for the <reset_source> end.
    //     See <Abstraction Levels of Interface Ends> for a description of abstraction
    //     levels and how they affect the behaviour of the Questa Verification IP.
    //
    // Arguments:
    //
    //    wire_level - Value = 1 if this end is WLM connected.
    //    TLM_level -  Value = 1 if this end is TLM connected.
    //------------------------------------------------------------------------------
    function void axi4_get_reset_source_abstraction_level
    (
        output bit         wire_level,
        output bit         TLM_level
    );
        axi4_get_reset_source_end_abstraction_level( wire_level, TLM_level );
    endfunction

    import "DPI-C" context function longint axi4_initialise_SystemVerilog
    (
        int    usage_code,
        string iface_version,
        output longint master_end,
        output longint slave_end,
        output longint clock_source_end,
        output longint reset_source_end,
        output longint _monitor_end,
        input int AXI4_ADDRESS_WIDTH,
        input int AXI4_RDATA_WIDTH,
        input int AXI4_WDATA_WIDTH,
        input int AXI4_ID_WIDTH,
        input int AXI4_USER_WIDTH,
        input int AXI4_REGION_MAP_SIZE
    );

    `ifndef MVC_axi4_VERSION
    `define MVC_axi4_VERSION ""
    `endif
    // Handle to the linkage
    (* elab_init *) longint _interface_ref =
                                axi4_initialise_SystemVerilog
                                (
                                    18102076,
                                    `MVC_axi4_VERSION,
                                    axi4_master_end,
                                    axi4_slave_end,
                                    axi4_clock_source_end,
                                    axi4_reset_source_end,
                                    axi4__monitor_end,
                                    AXI4_ADDRESS_WIDTH,
                                    AXI4_RDATA_WIDTH,
                                    AXI4_WDATA_WIDTH,
                                    AXI4_ID_WIDTH,
                                    AXI4_USER_WIDTH,
                                    AXI4_REGION_MAP_SIZE
                                ); // DPI call to create transactor (called at
                                     // elaboration time as initialiser)

    generate
    begin : questa_mvc_reporting
        bit report_available;

        // Function for getting a message from QUESTA_MVC. Returns 1 if a message was returned, 0 otherwise.
        import "DPI-C" questa_mvc_sv_get_report =  function bit get_report( input longint iface_ref,input longint recipient,
                                     output string category,     output string objectName,
                                     output string instanceName, output string error_no,
                                     output string typ,          output string mess );
        questa_mvc_reporter endPoint[longint];
        initial report_available = 0;

        always @report_available
        begin
            longint recipient;
            string category;
            string objectName;
            string instanceName;
            string severity;
            string mess;
            string error_no;

            if ( endPoint.first( recipient ) )
              begin
                do
                  begin
                      while ( get_report( _interface_ref, recipient, category, objectName, instanceName, error_no, severity, mess ) )
                        begin
                          endPoint[recipient].report_message( category, "axi4", 0, objectName, instanceName, error_no, severity, mess );
                        end
                  end
                while (endPoint.next(recipient));
              end
            report_available = 0;
        end

        import "DPI-C" context questa_mvc_register_end_point = function void questa_mvc_register_end_point( input longint iface_ref, input longint as_end, input string name );

        // A function for registering a reporter to capture any reports coming from as_end
        function automatic void register_end_point( input longint as_end, input questa_mvc_reporter rep = null );
            if ( rep != null )
              begin
                if ( ( rep.name == "" ) || ( rep.name == "NULL" ) )
                  begin
                    $display("Error: %m: Reporter passed to register_end_point has a reserved name. Neither an empty string nor the string 'NULL' can be used.");
                  end
                else
                  begin
                    questa_mvc_register_end_point( _interface_ref, as_end, rep.name );
                    endPoint[as_end] = rep;
                  end
              end
            else
              begin
                questa_mvc_register_end_point( _interface_ref, as_end, "NULL" );
                endPoint.delete( as_end );
              end
        endfunction

    end : questa_mvc_reporting
    endgenerate

