    bit [((AXI4_ADDRESS_WIDTH) - 1):0]  temp_static_fn_get_raddr_phase_info_addr;
    function void axi4_get_temp_static_fn_get_raddr_phase_info_addr( input int _d1, output bit  _value );
        _value = temp_static_fn_get_raddr_phase_info_addr[_d1];
