    function void axi4_set_temp_static_fn_get_raddr_phase_info_addr( input int _d1, input bit  _value );
        temp_static_fn_get_raddr_phase_info_addr[_d1] = _value;
    endfunction
    //-------------------------------------------------------------------------
    // Function: fn_get_raddr_phase_info
    //-------------------------------------------------------------------------
    // ---------------------------------------------------------------------------
    // A function to get valid read address phase information for outstanding read 
    // txn with input ARID.
    // 
    // Please note that this function should be called after completion of a read
    // address phase.
    // 
    // Inputs:
    // id - outstanding read transaction's id (ARID) whose info is requested
    // 
    // Outputs:
    // valid - Tells whether returned info is valid or not 
    // addr - returns starting address for read txn with input ~id~
    // num_beats_rcvd - returns number of read data beats received
    function automatic void fn_get_raddr_phase_info
    (
        inout bit valid,
        input bit [17:0] id,
        output bit [((AXI4_ADDRESS_WIDTH) - 1):0]  addr,
        output int num_beats_rcvd
    );
         fn_get_raddr_phase_info_C(valid,id,num_beats_rcvd);
        addr = temp_static_fn_get_raddr_phase_info_addr;
    endfunction

