    // 
    // Outputs:
    // addr - returns starting address for write txn with input ~id~
    function automatic void fn_get_waddr_phase_info
    (
        inout bit valid,
        input bit [17:0] id,
        output bit [((AXI4_ADDRESS_WIDTH) - 1):0]  addr
    );
         fn_get_waddr_phase_info_C(valid,id);
        addr = temp_static_fn_get_waddr_phase_info_addr;
    endfunction

