    function automatic void axi4_local_set_config_axi4lite_interface_from_SystemVerilog( ref bit config_axi4lite_interface_param );
            axi4_set_config_axi4lite_interface_from_SystemVerilog( _interface_ref,config_axi4lite_interface); // DPI call to imported task
        
            axi4_propagate_config_axi4lite_interface_from_SystemVerilog( _interface_ref ); // DPI call to imported task
    endfunction

    initial
    begin
        begin
            wait(_interface_ref != 0);
            forever
            begin
                @( * ) axi4_local_set_config_axi4lite_interface_from_SystemVerilog( config_axi4lite_interface );
            end
        end
    end

