    // num_beats_rcvd - returns number of read data beats received
    function automatic void fn_get_raddr_phase_info
    (
        inout bit valid,
        input bit [17:0] id,
        output bit [((AXI4_ADDRESS_WIDTH) - 1):0]  addr,
        output int num_beats_rcvd
    );
         fn_get_raddr_phase_info_C(valid,id,num_beats_rcvd);
        addr = temp_static_fn_get_raddr_phase_info_addr;
    endfunction

